<?php
namespace App\Models;
use App\Enums\PayoutStatus;use App\Enums\PayoutType;use App\Models\Concerns\BelongsToTenant;use App\Models\Concerns\HasAuditTrail;use Illuminate\Database\Eloquent\Concerns\HasUlids;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\HasMany;
class Payout extends Model{use BelongsToTenant,HasAuditTrail,HasUlids;protected $fillable=['cooperative_id','payout_batch_id','member_id','payable_type','payable_id','reference','idempotency_key','type','currency','amount_minor','beneficiary_name','bank_code','account_number_encrypted','account_number_last_four','scheduled_for','recurrence_rule','status','provider','provider_reference','failure_reason','created_by','reviewed_by','released_by','released_at','paid_at','metadata'];protected $hidden=['account_number_encrypted'];protected function casts():array{return ['type'=>PayoutType::class,'status'=>PayoutStatus::class,'amount_minor'=>'integer','scheduled_for'=>'datetime','released_at'=>'datetime','paid_at'=>'datetime','metadata'=>'array'];}public function events():HasMany{return $this->hasMany(PayoutEvent::class);}public function batch():\Illuminate\Database\Eloquent\Relations\BelongsTo{return $this->belongsTo(PayoutBatch::class,'payout_batch_id');}}
